def normalize_keyword_text(value):
    """Normalize text for simple rule-based article classification."""
    return f" {clean_text(str(value or '')).lower()} "


def unique_list(values):
    """Return values in first-seen order without duplicates."""
    seen = set()
    cleaned = []
    for value in values:
        key = str(value).strip().lower()
        if not key or key in seen:
            continue
        seen.add(key)
        cleaned.append(value)
    return cleaned


def match_rule_labels(text, rules):
    """Return all labels whose keyword rules are found in text."""
    matches = []
    for label, keywords in rules:
        if find_matches(text, [keyword.lower() for keyword in keywords]):
            matches.append(label)
    return unique_list(matches)


def first_or_none(values, default="none"):
    """Return a semicolon-friendly label list or default."""
    cleaned = [str(value).strip() for value in values if str(value).strip()]
    return "; ".join(cleaned) if cleaned else default


def classify_primary_topic(text, capital_events, development_stages, supply_signals, institutional_activity, financing_types, asset_strategy):
    """Choose one primary topic from the article classification signals."""
    capital_event_set = set(capital_events or [])
    development_stage_set = set(development_stages or [])
    financing_event_set = {
        "refinancing", "recapitalization", "construction_financing", "bridge_loan",
        "permanent_loan", "preferred_equity", "mezzanine_financing", "debt_extension",
    }
    institution_event_set = {
        "merger_acquisition", "joint_venture", "platform_investment", "other_capital_event",
    }
    transaction_event_set = {"acquisition", "disposition", "distress_sale"}
    explicit_execution_stage_set = {
        "construction_start", "under_construction", "delivery", "lease_up",
        "stabilization", "entitlement", "zoning", "permit", "planning_commission",
        "site_acquisition", "land_assembly", "redevelopment", "adaptive_reuse",
    }
    if capital_event_set & financing_event_set:
        return "capital_markets"
    if capital_event_set & institution_event_set:
        return "institutional_capital"
    if capital_event_set & transaction_event_set and not (development_stage_set & explicit_execution_stage_set):
        return "transaction_market"
    topic_hits = {
        "capital_markets": bool(financing_types and financing_types != ["none"]),
        "development_pipeline": bool(development_stage_set - {"none", "density_bonus"}),
        "supply_demand": bool(supply_signals and supply_signals != ["none"]),
        "institutional_capital": bool(set(institutional_activity) - {"none"}),
        "gp_activity": bool(find_matches(text, [" gp ", "sponsor", "developer", "joint venture", "partnership"])),
        "entitlement_policy": bool(set(development_stages) & {"entitlement", "zoning", "permit", "planning_commission", "density_bonus"}),
        "operations_property_management": bool(find_matches(text, ["property management", "operator", "operations", "renewal", "occupancy"])),
        "macro_financing": bool(find_matches(text, ["fed", "interest rate", "treasury", "inflation", "economy", "macro"])),
        "transaction_market": bool(set(capital_events) & {"acquisition", "disposition", "distress_sale", "merger_acquisition"}),
        "research_data": bool(find_matches(text, ["report", "survey", "index", "forecast", "research", "outlook"])),
    }
    for topic in PRIMARY_TOPIC_PRIORITY:
        if topic_hits.get(topic):
            return topic
    if asset_strategy and asset_strategy != ["unknown"]:
        return "research_data"
    return "other"


def get_secondary_topic(primary_topic, text, capital_events, development_stages, supply_signals, institutional_activity):
    """Add a secondary topic when the article has a meaningful second signal."""
    topic_candidates = []
    if primary_topic != "capital_markets" and capital_events and capital_events != ["none"]:
        topic_candidates.append("capital_markets")
    if primary_topic != "development_pipeline" and development_stages and development_stages != ["none"]:
        topic_candidates.append("development_pipeline")
    if primary_topic != "supply_demand" and supply_signals and supply_signals != ["none"]:
        topic_candidates.append("supply_demand")
    if primary_topic != "institutional_capital" and institutional_activity and institutional_activity != ["none"]:
        topic_candidates.append("institutional_capital")
    if primary_topic != "macro_financing" and find_matches(text, ["fed", "interest rate", "treasury", "inflation"]):
        topic_candidates.append("macro_financing")
    return "; ".join(unique_list(topic_candidates[:2])) or "none"


def classify_article_confidence(text, matched_groups):
    """Conservative confidence label for rule-based classification."""
    strong_hits = sum(1 for group in matched_groups if group and group not in [["none"], ["unknown"]])
    title_weighted_terms = [
        "refinance", "recap", "bridge loan", "construction loan", "joint venture",
        "acquires", "sells", "permit", "entitlement", "broke ground", "lease-up",
        "concession", "vacancy", "fannie mae", "freddie mac",
    ]
    if find_matches(text[:300], title_weighted_terms):
        return "high"
    if strong_hits >= 2:
        return "medium"
    if strong_hits == 1:
        return "low"
    return "unknown"


def build_classification_reason(primary_topic, capital_events, development_stages, supply_signals, institutional_activity, financing_types, confidence):
    """Explain why the rule-based classifier chose the labels."""
    reasons = []
    if capital_events and capital_events != ["none"]:
        reasons.append(f"Capital event keywords detected: {', '.join(capital_events[:3])}.")
    if financing_types and financing_types != ["none"]:
        reasons.append(f"Financing type keywords detected: {', '.join(financing_types[:3])}.")
    if development_stages and development_stages != ["none"]:
        reasons.append(f"Development-stage terms detected: {', '.join(development_stages[:3])}.")
    if supply_signals and supply_signals != ["none"]:
        reasons.append(f"Supply/demand terms detected: {', '.join(supply_signals[:3])}.")
    if institutional_activity and institutional_activity != ["none"]:
        reasons.append(f"Institutional activity terms detected: {', '.join(institutional_activity[:3])}.")
    if not reasons:
        reasons.append("No clear rule-based event keyword was detected.")
    reasons.append(f"Primary topic set to {primary_topic}; confidence {confidence}.")
    return " ".join(reasons)


def build_market_relevance_reason(article, primary_topic, market):
    """Short market relevance explanation for article-level classification."""
    if market and market != "Other / Unknown":
        return f"Market reference detected as {market}."
    if primary_topic in ["macro_financing", "capital_markets"]:
        return "No specific market detected; treated as broader capital markets context."
    return "No specific market detected; relevance remains broad."


def enrich_article_classification(article):
    """Add detailed rule-based classification fields to an article row."""
    text = normalize_keyword_text(" ".join([
        article.get("title", ""),
        article.get("article_text_sample", ""),
        article.get("topics", ""),
        article.get("matched_keywords", ""),
        article.get("market_signal", ""),
        article.get("strategic_angle", ""),
        article.get("reason_for_inclusion", ""),
    ]))
    capital_events = match_rule_labels(text, CAPITAL_EVENT_RULES) or ["none"]
    development_stages = match_rule_labels(text, DEVELOPMENT_STAGE_RULES) or ["none"]
    supply_signals = match_rule_labels(text, SUPPLY_DEMAND_RULES) or ["none"]
    institutional_activity = match_rule_labels(text, INSTITUTIONAL_ACTIVITY_RULES) or ["none"]
    financing_types = match_rule_labels(text, FINANCING_TYPE_RULES) or ["none"]
    asset_strategy = match_rule_labels(text, ASSET_STRATEGY_RULES) or ["unknown"]
    entity_roles = match_rule_labels(text, ENTITY_ROLE_RULES) or ["unknown"]
    primary_topic = classify_primary_topic(
        text,
        capital_events,
        development_stages,
        supply_signals,
        institutional_activity,
        financing_types,
        asset_strategy,
    )
    secondary_topic = get_secondary_topic(
        primary_topic,
        text,
        capital_events,
        development_stages,
        supply_signals,
        institutional_activity,
    )
    confidence = classify_article_confidence(
        text,
        [capital_events, development_stages, supply_signals, institutional_activity, financing_types],
    )
    market = article.get("market_focus") or "Other / Unknown"
    article.update({
        "primary_topic": primary_topic,
        "secondary_topic": secondary_topic,
        "capital_event_type": first_or_none(capital_events),
        "development_stage": first_or_none(development_stages),
        "supply_demand_signal": first_or_none(supply_signals),
        "institutional_activity_type": first_or_none(institutional_activity),
        "financing_type": first_or_none(financing_types),
        "asset_strategy": first_or_none(asset_strategy, "unknown"),
        "entity_role": first_or_none(entity_roles, "unknown"),
        "market_relevance_reason": build_market_relevance_reason(article, primary_topic, market),
        "classification_confidence": confidence,
        "classification_reason": build_classification_reason(
            primary_topic,
            capital_events,
            development_stages,
            supply_signals,
            institutional_activity,
            financing_types,
            confidence,
        ),
    })
    return article


def get_article_identity_key(article):
    """Return URL-first article identity key for integrity and dedupe checks."""
    url = normalize_article_url(article.get("url") or article.get("original_url") or "")
    if url:
        return f"url:{url}"
    return f"title:{normalize_article_title_for_history(article.get('title', ''))}"


def detect_source_url_mismatch(article):
    """Flag likely title/source/url cross-contamination for known fragile feeds."""
    source = str(article.get("source", "") or "").lower()
    url = str(article.get("url", "") or article.get("original_url", "") or "").lower()
    if not source or not url:
        return False
    expected_domains = [
        ("sf yimby", ["sfyimby", "yimby"]),
        ("urbanize la", ["urbanize.la", "la.urbanize"]),
        ("connect cre", ["connectcre"]),
        ("yield pro", ["yieldpro"]),
        ("commercial observer", ["commercialobserver"]),
        ("multifamily dive", ["multifamilydive"]),
        ("multi-housing news", ["multihousingnews"]),
    ]
    for source_hint, domain_hints in expected_domains:
        if source_hint in source and not any(domain in url for domain in domain_hints):
            return True
    return False


def apply_article_integrity_checks(articles):
    """Add conservative article identity integrity flags without merging metadata."""
    url_to_titles = {}
    title_to_urls = {}
    for article in articles:
        url = normalize_article_url(article.get("url") or article.get("original_url") or "")
        title_key = normalize_article_title_for_history(article.get("title", ""))
        if url and title_key:
            url_to_titles.setdefault(url, set()).add(title_key)
            title_to_urls.setdefault(title_key, set()).add(url)

    for article in articles:
        article["original_url"] = article.get("original_url") or article.get("url", "")
        reasons = []
        status = "valid"
        url = normalize_article_url(article.get("url") or article.get("original_url") or "")
        title_key = normalize_article_title_for_history(article.get("title", ""))
        if not article.get("title") or not article.get("source") or not url:
            status = "incomplete_metadata"
            reasons.append("missing title, source, or URL")
        if url and len(url_to_titles.get(url, set())) > 1:
            status = "url_title_mismatch"
            reasons.append("same URL appears with multiple normalized titles")
        if title_key and len(title_to_urls.get(title_key, set())) > 1 and status == "valid":
            status = "suspicious_duplicate"
            reasons.append("same normalized title appears with multiple URLs")
        if detect_source_url_mismatch(article):
            status = "url_title_mismatch"
            reasons.append("source name does not match expected URL domain")
        if status != "valid":
            if article.get("classification_confidence") == "high":
                article["classification_confidence"] = "medium"
            elif article.get("classification_confidence") == "medium":
                article["classification_confidence"] = "low"
        article["article_integrity_status"] = status
        article["article_integrity_reason"] = "; ".join(reasons) or "title/source/url metadata are internally consistent"
    return articles


def calculate_article_richness_score(article):
    """Score how much concrete evidence an article carries."""
    text = normalize_keyword_text(" ".join([
        article.get("title", ""),
        article.get("article_text_sample", ""),
        article.get("matched_keywords", ""),
        article.get("capital_event_type", ""),
        article.get("development_stage", ""),
        article.get("financing_type", ""),
    ]))
    score = 0
    if article.get("market_focus") and article.get("market_focus") != "Other / Unknown":
        score += 15
    if find_matches(text, ["$", "million", "billion", "units", "acre", "loan", "financing"]):
        score += 15
    if article.get("capital_event_type") not in ["", "none"]:
        score += 15
    if article.get("development_stage") not in ["", "none"]:
        score += 15
    if article.get("institutional_activity_type") not in ["", "none"]:
        score += 10
    if article.get("entity_role") not in ["", "unknown"]:
        score += 10
    if len(str(article.get("article_text_sample", ""))) >= 160:
        score += 10
    if article.get("source"):
        score += 10
    return min(100, score)


def calculate_strategic_relevance(article):
    """Score observed strategic behavior, not investment attractiveness."""
    title_text = normalize_keyword_text(article.get("title", ""))
    text = normalize_keyword_text(" ".join([
        article.get("title", ""),
        article.get("article_text_sample", ""),
        article.get("matched_keywords", ""),
        article.get("primary_topic", ""),
        article.get("capital_event_type", ""),
        article.get("development_stage", ""),
        article.get("institutional_activity_type", ""),
        article.get("asset_strategy", ""),
    ]))
    positive_rules = [
        (18, "sponsor expansion", ["expands", "expansion", "enters", "entry", "grows presence"]),
        (18, "multi-phase development", ["phase ii", "second phase", "next phase", "multi-phase", "phased"]),
        (18, "platform or fund activity", ["platform", "fund close", "capital raise", "launches fund"]),
        (16, "JV or partnership activity", ["joint venture", " jv ", "partnership"]),
        (16, "development continuation", ["construction begins", "broke ground", "under construction", "delivers", "opens"]),
        (15, "entitlement persistence", ["entitlement", "zoning", "permit", "density bonus", "planning commission"]),
        (14, "institutional acquisition behavior", ["acquires", "acquisition", "portfolio", "reit", "institutional investor"]),
        (12, "lease-up or absorption behavior", ["lease-up", "absorption", "concession", "occupancy"]),
        (10, "large-scale refinance tied to strategy", ["recapitalization", "recap", "refinancing", "bridge loan"]),
    ]
    negative_rules = [
        (-28, "event/webinar or promotion", ["webinar", "conference", "event", "register", "sponsored", "award", "recognition"]),
        (-22, "thin PR language", ["announces", "welcomes", "celebrates", "appoints", "promotes", "opens new office"]),
        (-45, "non-multifamily contamination", [
            "industrial", "warehouse", "logistics", "office lease", "retail center",
            "life sciences", "therapeutics", "commercialization", "halliburton",
            "propell", "energy", "power generation",
        ]),
        (-14, "generic commentary", ["commentary", "opinion", "podcast", "interview"]),
    ]
    score = 35
    reasons = []
    for points, reason, keywords in positive_rules:
        if find_matches(text, keywords):
            score += points
            reasons.append(reason)
    for points, reason, keywords in negative_rules:
        if find_matches(text, keywords):
            score += points
            reasons.append(reason)
    if "non-multifamily contamination" in reasons and not find_matches(text, ["multifamily", "apartment", "housing", "residential", "btr", "rental"]):
        score = min(score, 25)
    source = str(article.get("source", "") or "").lower()
    source_prone_to_page_bleed = any(source_name in source for source_name in ["sf yimby", "urbanize"])
    strong_capital_reasons = {"JV or partnership activity", "institutional acquisition behavior"}
    title_has_capital_signal = bool(find_matches(title_text, [
        "joint venture", " jv ", "partnership", "acquires", "acquisition",
        "sale", "sells", "divests", "financing", "loan", "refinance",
    ]))
    if source_prone_to_page_bleed and not title_has_capital_signal and any(reason in reasons for reason in strong_capital_reasons):
        score -= 25
        reasons.append("source feed cross-signal penalty")
    richness = calculate_article_richness_score(article)
    score += round(richness * 0.25)
    if article.get("article_integrity_status") != "valid":
        score -= 25
        reasons.append("integrity penalty")
    if article.get("classification_confidence") in ["low", "unknown"]:
        score -= 10
        reasons.append("classification confidence penalty")
    score = max(0, min(100, score))
    if not reasons:
        reasons.append("general market observation with limited strategic behavior evidence")
    return score, "; ".join(unique_list(reasons[:5])), richness


def enrich_signal_tuning_fields(articles):
    """Add integrity, richness, strategic relevance, and evidence scores."""
    apply_article_integrity_checks(articles)
    for article in articles:
        relevance_score, relevance_reason, richness_score = calculate_strategic_relevance(article)
        article["article_richness_score"] = richness_score
        article["strategic_relevance_score"] = relevance_score
        article["strategic_relevance_reason"] = relevance_reason
        if "source feed cross-signal penalty" in relevance_reason:
            if article.get("article_integrity_status") == "valid":
                article["article_integrity_status"] = "suspicious_duplicate"
                article["article_integrity_reason"] = "source-feed signal bleed suspected"
            if article.get("classification_confidence") == "high":
                article["classification_confidence"] = "medium"
            elif article.get("classification_confidence") == "medium":
                article["classification_confidence"] = "low"
        evidence_score = relevance_score
        if "Financing Risk" in str(article.get("strategic_angle", "")) and article.get("primary_topic") == "capital_markets":
            evidence_score -= 8
        if article.get("development_stage") not in ["", "none"] or article.get("institutional_activity_type") not in ["", "none"]:
            evidence_score += 6
        if article.get("article_integrity_status") != "valid":
            evidence_score -= 20
        if "source feed cross-signal penalty" in relevance_reason:
            evidence_score -= 25
        article["representative_evidence_score"] = max(0, min(100, evidence_score))
    return articles


def get_priority(relevance_score):
    """
    Convert the numeric relevance score into a simple research priority.

    This makes the CSV easier to scan:
    - High: strongest articles to read first
    - Medium: useful articles to review after High items
    - Low: passed the filter, but less urgent
    """
    if relevance_score >= 80:
        return "High"

    if relevance_score >= 60:
        return "Medium"

    return "Low"


def get_action_level(relevance_score):
    """
    Convert the relevance score into a daily briefing action level.

    This is more action-oriented than priority:
    - Must Read: read first today
    - Review: useful enough for the high-priority briefing file
    - Monitor: relevant, but less urgent
    """
    if relevance_score >= 85:
        return "Must Read"

    if relevance_score >= 70:
        return "Review"

    return "Monitor"


def get_market_focus(text):
    """
    Detect the market or geography mentioned in the article.

    The first matching rule wins. More specific markets are listed before
    broader regions, so Los Angeles is detected before California.
    """
    for rule in MARKET_FOCUS_RULES:
        if find_matches(text, rule["keywords"]):
            return rule["label"]

    return "Other / Unknown"


def get_market_focus_bonus(market_focus):
    """
    Add a small relevance-score bonus for target markets.

    This helps a daily briefing prioritize geographies that are often more
    important for US residential developer strategy.
    """
    for rule in MARKET_FOCUS_RULES:
        if rule["label"] == market_focus:
            return rule["bonus"]

    return 0


def extract_numbers(text):
    """
    Extract simple numeric market signals from article text.

    This is intentionally rule-based and beginner-friendly. It captures
    common real estate signals like percentages, basis points, dollar
    amounts, unit counts, rent values, and market-relevant years.
    """
    patterns = [
        r"\b\d+(?:\.\d+)?%",
        r"\b\d+(?:,\d{3})?\s?(?:bps|basis points?)\b",
        r"\$\s?\d+(?:,\d{3})*(?:\.\d+)?\s?(?:million|billion|m|b)?\b",
        r"\b\d+(?:,\d{3})*\s?(?:units|apartments|homes|rental units)\b",
        r"\$\s?\d+(?:,\d{3})*(?:\.\d+)?\s?(?:rent|monthly rent|per month)\b",
        r"\b20\d{2}\s?(?:deliveries|starts|pipeline|forecast|outlook)\b",
    ]
    extracted = []

    for pattern in patterns:
        extracted.extend(re.findall(pattern, text, flags=re.IGNORECASE))

    cleaned_numbers = []
    seen = set()

    for item in extracted:
        cleaned_item = clean_text(item)
        key = cleaned_item.lower()

        if key not in seen:
            seen.add(key)
            cleaned_numbers.append(cleaned_item)

    return cleaned_numbers


def get_market_signal(text, extracted_numbers):
    """
    Label the type of numeric market signal found in the article.

    The label is useful for quickly separating rent, vacancy, financing,
    supply, cost, concession, and transaction-size signals.
    """
    if not extracted_numbers:
        return "No Clear Numeric Signal"

    if find_matches(text, ["rent growth", "effective rent", "asking rent", "rent"]):
        return "Rent Growth Signal"

    if find_matches(text, ["vacancy", "occupancy"]):
        return "Vacancy Signal"

    if find_matches(text, ["cap rate", "capitalization rate"]):
        return "Cap Rate Signal"

    if find_matches(
        text,
        ["interest rate", "treasury yield", "sofr", "basis points", "bps", "debt"],
    ):
        return "Financing Cost Signal"

    if find_matches(
        text,
        ["starts", "construction starts", "deliveries", "units", "pipeline"],
    ):
        return "Supply / Starts Signal"

    if find_matches(
        text,
        ["construction cost", "labor cost", "material cost", "insurance cost"],
    ):
        return "Construction Cost Signal"

    if find_matches(text, ["concession", "concessions", "one month free"]):
        return "Concession Signal"

    if find_matches(
        text,
        ["acquisition", "sale", "transaction", "portfolio", "joint venture"],
    ):
        return "Deal Size Signal"

    return "No Clear Numeric Signal"


def get_strategic_angle(text):
    """
    Add practical strategy labels for a developer/investor reader.

    An article can have more than one angle. For example, a story about
    higher rates slowing new construction may be both Financing Risk and
    Supply Pressure.
    """
    strategic_angles = []

    financing_risk_terms = [
        "interest rate",
        "rate hike",
        "rate cut",
        "treasury yield",
        "sofr",
        "financing",
        "debt",
        "loan",
        "lending",
        "refinancing",
        "credit",
    ]
    supply_pressure_terms = [
        "new supply",
        "supply pipeline",
        "deliveries",
        "starts",
        "construction starts",
        "pipeline",
        "vacancy",
        "oversupply",
        "lease-up",
    ]
    rent_growth_demand_terms = [
        "rent growth",
        "effective rent",
        "asking rent",
        "occupancy",
        "absorption",
        "demand",
        "migration",
        "household formation",
        "concession",
        "concessions",
    ]
    regulation_risk_terms = [
        "rent control",
        "rent stabilization",
        "zoning",
        "permitting",
        "entitlement",
        "lihtc",
        "inclusionary zoning",
        "tenant protection",
        "environmental review",
    ]
    cost_control_terms = [
        "construction cost",
        "labor cost",
        "material cost",
        "modular construction",
        "prefabrication",
        "value engineering",
        "cost control",
        "insurance cost",
    ]
    institutional_flow_terms = [
        "blackstone",
        "brookfield",
        "institutional investor",
        "capital markets",
        "acquisition",
        "disposition",
        "sale",
        "joint venture",
        "recapitalization",
        "portfolio",
        "cap rate",
    ]
    developer_strategy_terms = [
        "developer",
        "development",
        "adaptive reuse",
        "office-to-residential",
        "conversion",
        "build-to-rent",
        "built-to-rent",
        "site acquisition",
        "land acquisition",
        "groundbreaking",
    ]

    if find_matches(text, financing_risk_terms):
        strategic_angles.append("Financing Risk")

    if find_matches(text, supply_pressure_terms):
        strategic_angles.append("Supply Pressure")

    if find_matches(text, rent_growth_demand_terms):
        strategic_angles.append("Rent Growth / Demand")

    if find_matches(text, regulation_risk_terms):
        strategic_angles.append("Regulation Risk")

    if find_matches(text, cost_control_terms):
        strategic_angles.append("Cost Control")

    if find_matches(text, institutional_flow_terms):
        strategic_angles.append("Institutional Flow")

    if find_matches(text, developer_strategy_terms):
        strategic_angles.append("Developer Strategy")

    if not strategic_angles:
        strategic_angles.append("Developer Strategy")

    return "; ".join(strategic_angles)


def get_decision_use(strategic_angle):
    """
    Convert strategic angles into daily tracking decisions.

    These labels are written from the user's point of view: what should a
    developer or strategy team do with this article?
    """
    decision_rules = [
        ("Financing Risk", "Track Financing Conditions"),
        ("Supply Pressure", "Track Supply Pipeline"),
        ("Rent Growth / Demand", "Track Rent / Vacancy Trend"),
        ("Regulation Risk", "Track Regulation Risk"),
        ("Cost Control", "Track Construction Cost"),
        ("Institutional Flow", "Track Institutional Capital Flow"),
        ("Developer Strategy", "Track Developer Strategy"),
    ]
    decision_uses = []

    for strategic_label, decision_label in decision_rules:
        if strategic_label in strategic_angle:
            decision_uses.append(decision_label)

    if not decision_uses:
        decision_uses.append("General Monitoring")

    return "; ".join(decision_uses)


def get_reason_for_inclusion(
    matched_keywords,
    relevance_score,
    strategic_angle,
    market_focus,
):
    """
    Write a short plain-English reason for why the article made the CSV.

    This is intentionally simple. It uses the same rule-based signals that
    powered scoring, so a beginner can understand and adjust it later.
    """
    if matched_keywords:
        keyword_text = ", ".join(matched_keywords[:3])
    else:
        keyword_text = "multiple multifamily strategy signals"

    if market_focus == "Other / Unknown":
        market_text = "a broad or unspecified market"
    else:
        market_text = market_focus

    return (
        f"Included because it scored {relevance_score} and mentions "
        f"{keyword_text}, with a {strategic_angle} angle for {market_text}."
    )


def get_strategic_implication(
    relevance_score,
    action_level,
    strategic_angle,
    market_focus,
    decision_use,
    market_signal,
    extracted_numbers,
    matched_keywords,
):
    """
    Generate a short rule-based strategic implication.

    This is not AI generation. It is a transparent sentence built from the
    article's existing labels, keywords, numbers, and score.
    """
    keyword_text = ", ".join(matched_keywords[:3]) if matched_keywords else "strategy signals"
    number_text = ", ".join(extracted_numbers[:3]) if extracted_numbers else "no specific number"

    if "Financing Risk" in strategic_angle or market_signal == "Financing Cost Signal":
        return (
            "Monitor financing conditions because the article includes "
            f"{keyword_text} and {number_text}, which may affect construction "
            "loans, refinancing risk, and exit cap rates."
        )

    if "Supply Pressure" in strategic_angle or market_signal == "Supply / Starts Signal":
        return (
            "Review this as a supply risk signal because it references new "
            f"deliveries, starts, pipeline, or permits in {market_focus}."
        )

    if "Rent Growth / Demand" in strategic_angle or market_signal in [
        "Rent Growth Signal",
        "Vacancy Signal",
        "Concession Signal",
    ]:
        return (
            "Track rent and vacancy conditions because the article points to "
            f"demand, occupancy, rent, vacancy, or concession signals in {market_focus}."
        )

    if "Regulation Risk" in strategic_angle:
        return (
            "Monitor regulation risk because the article may affect entitlement, "
            "zoning, rent rules, affordability requirements, or permitting strategy."
        )

    if "Cost Control" in strategic_angle or market_signal == "Construction Cost Signal":
        return (
            "Review for cost-control implications because the article may affect "
            "construction cost, labor, materials, insurance, or value engineering."
        )

    if "Institutional Flow" in strategic_angle or market_signal in [
        "Deal Size Signal",
        "Cap Rate Signal",
    ]:
        return (
            "Track this as institutional capital flow because it mentions major "
            "capital players, portfolio transactions, deal size, or cap-rate signals."
        )

    if "Developer Strategy" in strategic_angle:
        return (
            "Review for developer strategy because the article may inform site "
            "selection, product type, adaptive reuse, build-to-rent, or market entry."
        )

    return (
        f"Use for general monitoring because it scored {relevance_score}, is marked "
        f"{action_level}, and supports {decision_use}."
    )


def get_woomi_relevance(relevance_score, action_level, strategic_angle, market_signal):
    """
    Label how relevant the article is to US residential developer strategy.

    The label is intentionally simple and conservative for MVP use.
    """
    high_value_angles = [
        "Financing Risk",
        "Supply Pressure",
        "Regulation Risk",
        "Cost Control",
        "Institutional Flow",
        "Developer Strategy",
    ]
    high_value_signals = [
        "Cap Rate Signal",
        "Financing Cost Signal",
        "Supply / Starts Signal",
        "Deal Size Signal",
    ]

    if (
        relevance_score >= 85
        or action_level == "Must Read"
        or any(angle in strategic_angle for angle in high_value_angles)
        and market_signal in high_value_signals
    ):
        return "High relevance to US residential developer strategy"

    if relevance_score >= 60 or action_level == "Review":
        return "Medium relevance to market monitoring"

    return "Low relevance / background information"


def get_recommended_next_step(woomi_relevance, action_level, market_signal):
    """
    Recommend a simple next step for a daily or weekly strategy workflow.
    """
    if action_level == "Must Read":
        return "Read full article"

    if woomi_relevance == "High relevance to US residential developer strategy":
        return "Add to weekly strategy memo"

    if action_level == "Review":
        return "Track source for follow-up"

    if market_signal != "No Clear Numeric Signal":
        return "Monitor only"

    return "Ignore unless repeated"


def get_residential_sector(text):
    """Detect the most specific residential sector from article text."""
    text_lower = text.lower()

    for sector, keywords in RESIDENTIAL_SECTOR_KEYWORDS.items():
        if any(keyword in text_lower for keyword in keywords):
            return sector

    if "residential" in text_lower or "housing" in text_lower:
        return "General Residential"

    return "General Residential"


def get_residential_sector_bonus(residential_sector):
    """Return a modest scoring bonus for residential-sector relevance."""
    return RESIDENTIAL_SECTOR_BONUSES.get(residential_sector, 0)


def score_article(source, title, summary, article_text_sample="", source_category=""):
    """
    Score article relevance from 0 to 100.

    Scoring idea:
    - Strong multifamily terms are the most important signal.
    - Development, market data, capital markets, and named players add value.
    - Broad policy articles are kept only when they connect back to multifamily,
      development, finance, or market intelligence.
    """
    text = f"{title} {summary} {article_text_sample}".lower()

    core_matches = find_matches(text, MULTIFAMILY_CORE_KEYWORDS)
    development_matches = find_matches(text, DEVELOPMENT_KEYWORDS)
    market_matches = find_matches(text, MARKET_INTELLIGENCE_KEYWORDS)
    capital_matches = find_matches(text, CAPITAL_MARKETS_KEYWORDS)
    player_matches = find_matches(text, PLAYER_KEYWORDS)
    policy_matches = find_matches(text, POLICY_KEYWORDS)
    us_matches = find_matches(text, US_MARKET_KEYWORDS)
    low_value_matches = find_matches(text, LOW_VALUE_POLICY_KEYWORDS)
    market_focus = get_market_focus(text)
    market_focus_bonus = get_market_focus_bonus(market_focus)
    residential_sector = get_residential_sector(text)
    extracted_numbers = extract_numbers(text)
    market_signal = get_market_signal(text, extracted_numbers)

    score = 0

    # Source-category bonuses improve prioritization for institutional-grade
    # sources, but keyword relevance still drives whether an article is saved.
    score += SOURCE_CATEGORY_BONUSES.get(source_category, 0)

    score += min(len(core_matches) * 18, 40)
    score += min(len(development_matches) * 8, 24)
    score += min(len(market_matches) * 8, 24)
    score += min(len(capital_matches) * 7, 20)
    score += min(len(player_matches) * 10, 20)
    score += min(len(policy_matches) * 5, 12)
    score += min(len(us_matches) * 4, 8)
    score += market_focus_bonus
    score += get_residential_sector_bonus(residential_sector)

    # Numeric market signals make an article more useful as research data.
    if extracted_numbers:
        score += 5

    # These signal types are especially important for developer strategy.
    if market_signal in [
        "Cap Rate Signal",
        "Financing Cost Signal",
        "Supply / Starts Signal",
    ]:
        score += 5

    if core_matches and (development_matches or market_matches or capital_matches):
        score += 12

    if player_matches and (capital_matches or development_matches):
        score += 10

    if policy_matches and not core_matches and not development_matches:
        score -= 18

    if low_value_matches and not core_matches:
        score -= 15

    non_residential_terms = [
        "industrial", "warehouse", "logistics", "office lease", "office tower",
        "retail center", "shopping center", "hotel only", "life sciences",
        "therapeutics", "commercialization", "halliburton", "propell",
        "energy", "power generation",
    ]
    residential_context_terms = [
        "multifamily", "apartment", "apartments", "residential", "housing",
        "rental", "student housing", "senior housing", "build-to-rent",
    ]
    if find_matches(text, non_residential_terms) and not find_matches(text, residential_context_terms):
        score -= 28
    if "connect cre" in str(source or "").lower() and find_matches(text, non_residential_terms) and not core_matches:
        score -= 18

    score = max(0, min(score, 100))

    all_matches = (
        core_matches
        + development_matches
        + market_matches
        + capital_matches
        + player_matches
        + policy_matches
    )

    return score, sorted(set(all_matches)), extracted_numbers, market_signal


def should_keep_article(
    source,
    title,
    summary,
    score,
    article_text_sample="",
    source_category="",
):
    """
    Decide whether an article is useful enough to save.

    This is stricter than a simple keyword match. It requires:
    1. A minimum score, and
    2. At least one direct multifamily signal OR a combination of developer,
       market, capital, or player intelligence signals.
    """
    text = f"{title} {summary} {article_text_sample}".lower()

    has_core = bool(find_matches(text, MULTIFAMILY_CORE_KEYWORDS))
    has_development = bool(find_matches(text, DEVELOPMENT_KEYWORDS))
    has_market = bool(find_matches(text, MARKET_INTELLIGENCE_KEYWORDS))
    has_capital = bool(find_matches(text, CAPITAL_MARKETS_KEYWORDS))
    has_player = bool(find_matches(text, PLAYER_KEYWORDS))
    has_policy = bool(find_matches(text, POLICY_KEYWORDS))

    # Articles below the minimum relevance score are excluded from the CSV.
    if score < MIN_RELEVANCE_SCORE:
        return False

    if has_core:
        return True

    if (
        (source in HIGH_VALUE_SOURCES or source_category in HIGH_VALUE_SOURCE_CATEGORIES)
        and (has_development or has_market or has_capital)
    ):
        return True

    if has_player and (has_development or has_capital):
        return True

    if has_policy and (has_development or has_market or has_capital):
        return True

    return False


# ---------------------------------------------------------
# 5. Fetch one RSS feed
# ---------------------------------------------------------

def get_source_quality_label(fetch_status, entries_found, articles_saved, source_url):
    """Label source quality for the source-health report."""
    if fetch_status == "Disabled":
        return "Disabled / Registered"

    if not source_url:
        return "Placeholder / Needs Review"

    if fetch_status == "Failed":
        return "Failing"

    if articles_saved >= 3:
        return "High Value"

    if articles_saved >= 1:
        return "Useful"

    if entries_found > 0:
        return "Watch"

    return "Failing"


def add_source_health_row(
    source_name,
    source_category,
    source_url,
    fetch_status,
    entries_found,
    articles_saved,
    error_message="",
    platform_type="Other",
    source_tier="",
    coverage_focus="",
    enabled=True,
):
    """Store one source-health row for later CSV and Markdown output."""
    SOURCE_HEALTH_ROWS.append({
        "source_name": source_name,
        "source_category": source_category,
        "source_tier": source_tier,
        "coverage_focus": coverage_focus,
        "enabled": "Yes" if enabled else "No",
        "platform_type": platform_type,
        "source_url": source_url,
        "fetch_status": fetch_status,
        "entries_found": entries_found,
        "articles_saved": articles_saved,
        "error_message": error_message,
        "source_quality_label": get_source_quality_label(
            fetch_status,
            entries_found,
            articles_saved,
            source_url,
        ),
    })


# ---------------------------------------------------------
# 6. RSS / article collection
# ---------------------------------------------------------

def fetch_feed(feed_info):
    """Read one RSS feed and return relevant article dictionaries."""
    source = feed_info.get("source_name") or feed_info["source"]
    url = feed_info.get("source_url") or feed_info.get("rss_url") or feed_info.get("url", "")
    source_category = feed_info.get("source_category") or feed_info.get("category", "Uncategorized")
    platform_type = feed_info.get("platform_type", "Other")
    source_tier = feed_info.get("source_tier", "")
    coverage_focus = feed_info.get("coverage_focus", "")
    enabled = feed_info.get("enabled", True)
    articles = []

    if not enabled:
        print(f"[Info] Disabled source registered for review: {source}")
        add_source_health_row(
            source,
            source_category,
            url,
            "Disabled",
            0,
            0,
            "Registered source is disabled until a public feed is confirmed",
            platform_type,
            source_tier,
            coverage_focus,
            enabled,
        )
        return articles

    if not url:
        print(f"[Warning] Placeholder source needs RSS review: {source}")
        add_source_health_row(
            source,
            source_category,
            url,
            "Placeholder",
            0,
            0,
            "Source URL not yet confirmed",
            platform_type,
            source_tier,
            coverage_focus,
            enabled,
        )
        return articles

    try:
        feed = feedparser.parse(url, request_headers=RSS_REQUEST_HEADERS)
        entries_found = len(feed.entries)
        error_message = ""

        if feed.bozo and not feed.entries:
            error_message = "RSS parsing issue"
            print(f"[Warning] RSS parsing issue: {source}")

        for entry in feed.entries:
            title = clean_text(entry.get("title", ""))
            link = entry.get("link", "").strip()
            summary = clean_text(
                entry.get("summary", "")
                or entry.get("description", "")
                or entry.get("subtitle", "")
            )
            published = (
                entry.get("published", "")
                or entry.get("updated", "")
                or ""
            )

            relevance_score, matched_keywords, extracted_numbers, market_signal = score_article(
                source,
                title,
                summary,
                source_category=source_category,
            )

            # The largest possible market-signal bonus is 10 points.
            # If the RSS-only score is far below the threshold, we skip page
            # fetching to keep the script reasonably fast.
            if relevance_score < MIN_RELEVANCE_SCORE - 10:
                continue

            article_text = fetch_article_text(link)
            article_text_sample = get_article_text_sample(article_text)

            # Score again after article-page text is available. The sample may
            # contain useful numbers or market terms that were missing from RSS.
            relevance_score, matched_keywords, extracted_numbers, market_signal = score_article(
                source,
                title,
                summary,
                article_text_sample,
                source_category,
            )

            if not should_keep_article(
                source,
                title,
                summary,
                relevance_score,
                article_text_sample,
                source_category,
            ):
                continue

            combined_text = f"{title} {summary} {article_text_sample}".lower()
            matched_topics = classify_article(combined_text)
            strategic_angle = get_strategic_angle(combined_text)
            market_focus = get_market_focus(combined_text)
            residential_sector = get_residential_sector(combined_text)
            action_level = get_action_level(relevance_score)
            decision_use = get_decision_use(strategic_angle)
            strategic_implication = get_strategic_implication(
                relevance_score,
                action_level,
                strategic_angle,
                market_focus,
                decision_use,
                market_signal,
                extracted_numbers,
                matched_keywords,
            )
            woomi_relevance = get_woomi_relevance(
                relevance_score,
                action_level,
                strategic_angle,
                market_signal,
            )
            recommended_next_step = get_recommended_next_step(
                woomi_relevance,
                action_level,
                market_signal,
            )

            article = {
                "collected_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                "source": source,
                "source_category": source_category,
                "source_tier": source_tier,
                "coverage_focus": coverage_focus,
                "platform_type": platform_type,
                "residential_sector": residential_sector,
                "published": published,
                "relevance_score": relevance_score,
                "priority": get_priority(relevance_score),
                "action_level": action_level,
                "market_focus": market_focus,
                "strategic_angle": strategic_angle,
                "decision_use": decision_use,
                "strategic_implication": strategic_implication,
                "woomi_relevance": woomi_relevance,
                "recommended_next_step": recommended_next_step,
                "reason_for_inclusion": get_reason_for_inclusion(
                    matched_keywords,
                    relevance_score,
                    strategic_angle,
                    market_focus,
                ),
                "market_signal": market_signal,
                "extracted_numbers": "; ".join(extracted_numbers[:12]),
                "article_text_sample": article_text_sample,
                "topics": "; ".join(matched_topics),
                "matched_keywords": "; ".join(matched_keywords[:12]),
                "title": title,
                "url": link,
            }

            articles.append(article)

        fetch_status = "OK"
        if feed.bozo and not feed.entries:
            fetch_status = "Failed"

        add_source_health_row(
            source,
            source_category,
            url,
            fetch_status,
            entries_found,
            len(articles),
            error_message,
            platform_type,
            source_tier,
            coverage_focus,
            enabled,
        )

    except Exception as error:
        print(f"[Error] Failed to collect {source}: {error}")
        add_source_health_row(
            source,
            source_category,
            url,
            "Failed",
            0,
            len(articles),
            str(error),
            platform_type,
            source_tier,
            coverage_focus,
            enabled,
        )

    return articles


# ---------------------------------------------------------
# 7. Filtering and scoring
# ---------------------------------------------------------

def remove_duplicates(articles):
    """Remove duplicate articles using URL first, then normalized or near-match title."""
    seen_urls = set()
    seen_titles = set()
    kept_title_keys = []
    unique_articles = []

    for article in articles:
        url_key = normalize_article_url(article.get("url", ""))
        title_key = normalize_article_title_for_history(article.get("title", ""))

        if url_key and url_key in seen_urls:
            continue
        if title_key and title_key in seen_titles:
            continue
        if title_key:
            title_tokens = set(title_key.split())
            near_duplicate = False
            for kept_title_key in kept_title_keys:
                kept_tokens = set(kept_title_key.split())
                if not title_tokens or not kept_tokens:
                    continue
                similarity = len(title_tokens & kept_tokens) / len(title_tokens | kept_tokens)
                if similarity >= 0.85:
                    near_duplicate = True
                    break
            if near_duplicate:
                continue

        if url_key:
            seen_urls.add(url_key)
        if title_key:
            seen_titles.add(title_key)
            kept_title_keys.append(title_key)
        unique_articles.append(article)

    return unique_articles


# ---------------------------------------------------------
# 6. Shared utility functions
# ---------------------------------------------------------

# ---------------------------------------------------------
# 12. Archive / output helpers
# ---------------------------------------------------------

def get_dated_output_dir(run_timestamp):
    """Return output/runs/YYYY-MM-DD for dated archive files."""
    run_date = run_timestamp.strftime(DATE_FOLDER_FORMAT)
    return os.path.join(RUNS_DIR, run_date)


def get_archive_path(latest_path, dated_output_dir):
    """Build the dated archive path for a latest output file."""
    return os.path.join(dated_output_dir, os.path.basename(latest_path))


def make_run_id(run_timestamp):
    """Create a stable, readable run id for this collector execution."""
    base = run_timestamp.strftime("%Y%m%d-%H%M%S")
    digest = hashlib.sha1(base.encode("utf-8")).hexdigest()[:8]
    return f"{base}-{digest}"


def set_current_run_context(run_timestamp):
    """Store run metadata used by centralized CSV writers and manifests."""
    CURRENT_RUN_CONTEXT["run_id"] = make_run_id(run_timestamp)
    CURRENT_RUN_CONTEXT["run_date"] = run_timestamp.strftime(DATE_FOLDER_FORMAT)
    CURRENT_RUN_CONTEXT["run_timestamp"] = run_timestamp.strftime(TIMESTAMP_FORMAT)


def normalize_article_url(value):
    """Normalize URL for cross-run duplicate checks."""
    text = str(value or "").strip().lower()
    if not text:
        return ""
    text = text.split("#", 1)[0]
    text = text.split("?", 1)[0]
    return text.rstrip("/")


def normalize_article_title_for_history(value):
    """Normalize article titles for cross-run duplicate checks."""
    text = unescape(str(value or "")).lower()
    text = re.sub(r"[^a-z0-9]+", " ", text)
    return re.sub(r"\s+", " ", text).strip()


def article_history_keys(rows):
    """Return URL and normalized-title keys from existing article rows."""
    url_keys = set()
    title_keys = set()
    for row in rows:
        url_key = normalize_article_url(row.get("url", ""))
        title_key = normalize_article_title_for_history(row.get("title", ""))
        if url_key:
            url_keys.add(url_key)
        if title_key:
            title_keys.add(title_key)
    return url_keys, title_keys


def classify_new_articles_for_manifest(articles, previous_article_rows):
    """
    Count new vs duplicate articles against the prior latest articles.csv.

    Latest output files still update every run; this only prevents confusing
    run accounting by separating new observations from already-seen articles.
    """
    seen_urls, seen_titles = article_history_keys(previous_article_rows)
    new_count = 0
    duplicate_count = 0
    for article in articles:
        url_key = normalize_article_url(article.get("url", ""))
        title_key = normalize_article_title_for_history(article.get("title", ""))
        is_duplicate = bool((url_key and url_key in seen_urls) or (title_key and title_key in seen_titles))
        article["previously_seen_article"] = "Yes" if is_duplicate else "No"
        if is_duplicate:
            duplicate_count += 1
        else:
            new_count += 1
        if url_key:
            seen_urls.add(url_key)
        if title_key:
            seen_titles.add(title_key)
    return new_count, duplicate_count


def add_run_fields_to_rows(fieldnames, rows):
    """Add run_id and run_date to CSV rows without touching business logic."""
    output_fieldnames = list(fieldnames)
    for run_field in ["run_id", "run_date"]:
        if run_field not in output_fieldnames:
            output_fieldnames.insert(0, run_field)
    enriched_rows = []
    for row in rows:
        enriched = dict(row)
        enriched["run_id"] = enriched.get("run_id") or CURRENT_RUN_CONTEXT.get("run_id", "")
        enriched["run_date"] = enriched.get("run_date") or CURRENT_RUN_CONTEXT.get("run_date", "")
        enriched_rows.append(enriched)
    return output_fieldnames, enriched_rows


def write_csv_file(path, fieldnames, rows):
    """Write one CSV file to the requested path."""
    os.makedirs(os.path.dirname(path), exist_ok=True)

    with open(path, mode="w", newline="", encoding="utf-8-sig") as file:
        writer = csv.DictWriter(file, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)


def write_text_file(path, lines):
    """Write a Markdown/text file to the requested path."""
    os.makedirs(os.path.dirname(path), exist_ok=True)

    with open(path, mode="w", encoding="utf-8") as file:
        file.write("\n".join(lines))


def write_csv_outputs(path, fieldnames, rows, dated_output_dir):
    """
    Write a latest CSV file and, when enabled, a dated archive copy.

    Latest files stay directly in output/ for convenience. Dated files go to
    output/runs/YYYY-MM-DD/ so prior runs are easier to compare later.
    """
    output_fieldnames, enriched_rows = add_run_fields_to_rows(fieldnames, rows)

    write_csv_file(path, output_fieldnames, enriched_rows)

    if SAVE_DATED_OUTPUT:
        write_csv_file(get_archive_path(path, dated_output_dir), output_fieldnames, enriched_rows)


def list_generated_archive_files(dated_output_dir):
    """List generated files inside today's archive folder."""
    if not os.path.isdir(dated_output_dir):
        return []
    return sorted(
        name for name in os.listdir(dated_output_dir)
        if os.path.isfile(os.path.join(dated_output_dir, name))
    )


def write_run_manifest_json(dated_output_dir):
    """Write output/runs/YYYY-MM-DD/run_manifest.json for this run."""
    manifest_path = os.path.join(dated_output_dir, "run_manifest.json")
    output_files = list_generated_archive_files(dated_output_dir)
    if "run_manifest.json" not in output_files:
        output_files.append("run_manifest.json")
        output_files = sorted(output_files)
    manifest = {
        "run_id": CURRENT_RUN_CONTEXT.get("run_id", ""),
        "run_date": CURRENT_RUN_CONTEXT.get("run_date", ""),
        "run_timestamp": CURRENT_RUN_CONTEXT.get("run_timestamp", ""),
        "article_count": CURRENT_RUN_MANIFEST_STATS.get("article_count", 0),
        "new_article_count": CURRENT_RUN_MANIFEST_STATS.get("new_article_count", 0),
        "duplicate_article_count": CURRENT_RUN_MANIFEST_STATS.get("duplicate_article_count", 0),
        "output_files_generated": output_files,
    }
    os.makedirs(dated_output_dir, exist_ok=True)
    with open(manifest_path, mode="w", encoding="utf-8") as file:
        json.dump(manifest, file, ensure_ascii=False, indent=2)
    return manifest_path


def read_csv_file(path):
    """Read a CSV file into a list of dictionaries."""
    if not os.path.exists(path):
        return []

    with open(path, mode="r", newline="", encoding="utf-8-sig") as file:
        return list(csv.DictReader(file))


def read_csv_fieldnames(path):
    """Read only the header row from a CSV file."""
    if not os.path.exists(path):
        return []

    with open(path, mode="r", newline="", encoding="utf-8-sig") as file:
        reader = csv.DictReader(file)
        return reader.fieldnames or []


def normalize_costar_column_name(name):
    """Normalize a manually exported column name for flexible matching."""
    return re.sub(r"[^a-z0-9]+", "", str(name).strip().lower())


def get_costar_row_value(row, candidate_names):
    """Return the first non-empty value from a row using flexible column names."""
    normalized_row = {
        normalize_costar_column_name(key): value
        for key, value in row.items()
    }

    for candidate in candidate_names:
        value = normalized_row.get(normalize_costar_column_name(candidate), "")
        if value is None:
            continue
        text_value = clean_text(str(value))
        if text_value:
            return text_value

    return ""


def read_costar_csv_rows(path):
    """Read a manually exported CoStar CSV using common encodings."""
    last_error = None
    for encoding in ["utf-8-sig", "utf-8", "cp1252"]:
        try:
            with open(path, mode="r", newline="", encoding=encoding) as file:
                return list(csv.DictReader(file))
        except UnicodeDecodeError as error:
            last_error = error

    raise last_error or ValueError("Unable to read CSV file")


def read_costar_excel_rows(path):
    """Read a manually exported CoStar Excel file when pandas support exists."""
    try:
        import pandas as pd
    except Exception as error:
        raise RuntimeError(
            "Excel intake requires pandas and an Excel engine such as openpyxl."
        ) from error

    dataframe = pd.read_excel(path)
    dataframe = dataframe.fillna("")
    return dataframe.to_dict("records")


def read_costar_intake_rows(path):
    """Read supported CoStar intake files without any web scraping."""
    extension = os.path.splitext(path)[1].lower()

    if extension == ".csv":
        return read_costar_csv_rows(path)

    if extension in {".xlsx", ".xls"}:
        return read_costar_excel_rows(path)

    raise ValueError("Unsupported CoStar intake file type")


def infer_costar_residential_sector(text, asset_type):
    """Prefer CoStar asset type, then fall back to existing sector detection."""
    asset_type_lower = str(asset_type).lower()
    combined_text = f"{asset_type} {text}".lower()

    if "student" in combined_text:
        return "Student Housing"
    if "senior" in combined_text:
        return "Senior Housing"
    if "affordable" in combined_text:
        return "Affordable Housing"
    if any(token in combined_text for token in ["build-to-rent", "built-to-rent", "btr", "single-family rental", "sfr"]):
        return "Build-to-Rent / SFR"
    if any(token in asset_type_lower for token in ["multifamily", "apartment", "residential"]):
        return "Multifamily"

    return get_residential_sector(combined_text)


def normalize_costar_intake_row(row, file_name, row_number):
    """Convert one manual CoStar row into the existing article schema."""
    title = get_costar_row_value(row, [
        "title",
        "headline",
        "article title",
        "report title",
        "name",
    ])
    summary = get_costar_row_value(row, [
        "summary",
        "snippet",
        "description",
        "abstract",
        "body",
        "notes",
        "excerpt",
    ])
    published = get_costar_row_value(row, [
        "published_date",
        "published",
        "publication date",
        "article date",
        "date",
        "posted",
    ])
    url_or_reference = get_costar_row_value(row, [
        "url",
        "link",
        "article url",
        "source url",
        "reference",
        "report link",
        "costar url",
    ])
    market = get_costar_row_value(row, [
        "market",
        "metro",
        "city",
        "submarket",
        "location",
    ])
    region = get_costar_row_value(row, [
        "region",
        "state",
        "geography",
        "county",
    ])
    asset_type = get_costar_row_value(row, [
        "asset_type",
        "asset type",
        "property type",
        "sector",
        "use",
    ])
    raw_category = get_costar_row_value(row, [
        "raw_category",
        "category",
        "topic",
        "topics",
        "type",
        "tag",
        "tags",
    ])

    missing_fields = []
    if not title:
        missing_fields.append("title")
        return None, missing_fields

    article_text_sample = get_article_text_sample(summary)
    combined_text = " ".join([
        title,
        summary,
        market,
        region,
        asset_type,
        raw_category,
    ])
    combined_lower = combined_text.lower()
    source_category = "Manual Licensed Intake"

    relevance_score, matched_keywords, extracted_numbers, market_signal = score_article(
        "CoStar",
        title,
        summary,
        article_text_sample,
        source_category=source_category,
    )
    relevance_score = max(relevance_score, 65)
    market_focus = market or region or get_market_focus(combined_lower)
    residential_sector = infer_costar_residential_sector(combined_text, asset_type)
    matched_topics = classify_article(combined_lower)
    strategic_angle = get_strategic_angle(combined_lower)
    action_level = get_action_level(relevance_score)
    decision_use = get_decision_use(strategic_angle)
    if raw_category and raw_category not in matched_topics:
        matched_topics.append(raw_category)

    reference = url_or_reference or f"CoStar manual export: {file_name} row {row_number}"

    return {
        "collected_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "source": "CoStar",
        "source_category": source_category,
        "platform_type": "Manual Export",
        "residential_sector": residential_sector,
        "published": published,
        "relevance_score": relevance_score,
        "priority": get_priority(relevance_score),
        "action_level": action_level,
        "market_focus": market_focus,
        "strategic_angle": strategic_angle,
        "decision_use": decision_use,
        "strategic_implication": get_strategic_implication(
            relevance_score,
            action_level,
            strategic_angle,
            market_focus,
            decision_use,
            market_signal,
            extracted_numbers,
            matched_keywords,
        ),
        "woomi_relevance": get_woomi_relevance(
            relevance_score,
            action_level,
            strategic_angle,
            market_signal,
        ),
        "recommended_next_step": "Analyst review of manually exported CoStar source",
        "reason_for_inclusion": (
            "Included from a manually exported CoStar file. "
            "No CoStar scraping, login automation, or paywall bypass was used."
        ),
        "market_signal": market_signal,
        "extracted_numbers": "; ".join(extracted_numbers[:12]),
        "article_text_sample": article_text_sample,
        "topics": "; ".join(matched_topics),
        "matched_keywords": "; ".join(matched_keywords[:12]),
        "title": title,
        "url": reference,
    }, missing_fields


def reset_costar_intake_diagnostics():
    """Clear CoStar intake diagnostics before each collector run."""
    COSTAR_INTAKE_DIAGNOSTIC_ROWS.clear()
    COSTAR_INTAKE_SUMMARY.update({
        "files_loaded": 0,
        "rows_loaded": 0,
        "rows_accepted": 0,
        "rows_skipped": 0,
        "missing_required_fields": "",
    })


def load_costar_intake_files():
    """
    Load manually exported CoStar CSV/XLS/XLSX files from input/costar/.

    This function is intentionally offline-only. It never logs in, scrapes,
    calls CoStar, or attempts to bypass subscription controls.
    """
    reset_costar_intake_diagnostics()
    os.makedirs(COSTAR_INPUT_DIR, exist_ok=True)

    supported_extensions = {".csv", ".xlsx", ".xls"}
    intake_files = sorted(
        os.path.join(COSTAR_INPUT_DIR, file_name)
        for file_name in os.listdir(COSTAR_INPUT_DIR)
        if os.path.isfile(os.path.join(COSTAR_INPUT_DIR, file_name))
        and os.path.splitext(file_name)[1].lower() in supported_extensions
    )
    costar_articles = []
    missing_field_counter = Counter()
    generated_at = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    if not intake_files:
        COSTAR_INTAKE_DIAGNOSTIC_ROWS.append({
            "generated_at": generated_at,
            "file_name": "",
            "file_type": "",
            "file_status": "no files",
            "rows_loaded": 0,
            "rows_accepted": 0,
            "rows_skipped": 0,
            "missing_required_fields": "",
            "notes": f"No supported CoStar files found in {COSTAR_INPUT_DIR}.",
        })
        return costar_articles

    for path in intake_files:
        file_name = os.path.basename(path)
        file_type = os.path.splitext(path)[1].lower().lstrip(".")
        rows_loaded = 0
        rows_accepted = 0
        rows_skipped = 0
        missing_fields_for_file = Counter()
        status = "success"
        notes = ""

        try:
            rows = read_costar_intake_rows(path)
            rows_loaded = len(rows)
        except Exception as error:
            status = "error"
            notes = str(error)
            rows = []

        for row_number, row in enumerate(rows, start=2):
            article, missing_fields = normalize_costar_intake_row(row, file_name, row_number)
            if missing_fields:
                rows_skipped += 1
                missing_fields_for_file.update(missing_fields)
                missing_field_counter.update(missing_fields)
                continue

            if article:
                rows_accepted += 1
                costar_articles.append(article)
            else:
                rows_skipped += 1

        if status == "success" and rows_accepted == 0 and rows_loaded > 0:
            status = "no accepted rows"
            notes = "Rows were loaded, but no row had the required title field."

        COSTAR_INTAKE_DIAGNOSTIC_ROWS.append({
            "generated_at": generated_at,
            "file_name": file_name,
            "file_type": file_type,
            "file_status": status,
            "rows_loaded": rows_loaded,
            "rows_accepted": rows_accepted,
            "rows_skipped": rows_skipped,
            "missing_required_fields": "; ".join(sorted(missing_fields_for_file)),
            "notes": notes,
        })

        if status in {"success", "no accepted rows"}:
            COSTAR_INTAKE_SUMMARY["files_loaded"] += 1
        COSTAR_INTAKE_SUMMARY["rows_loaded"] += rows_loaded
        COSTAR_INTAKE_SUMMARY["rows_accepted"] += rows_accepted
        COSTAR_INTAKE_SUMMARY["rows_skipped"] += rows_skipped

    COSTAR_INTAKE_SUMMARY["missing_required_fields"] = "; ".join(
        sorted(missing_field_counter)
    )

    if COSTAR_INTAKE_SUMMARY["rows_accepted"] > 0:
        add_source_health_row(
            "CoStar",
            "Manual Licensed Intake",
            COSTAR_INPUT_DIR,
            "OK",
            COSTAR_INTAKE_SUMMARY["rows_loaded"],
            COSTAR_INTAKE_SUMMARY["rows_accepted"],
            "Manual export intake only; no scraping performed.",
            "Manual Export",
        )

    return costar_articles


def generate_costar_intake_report_outputs(dated_output_dir):
    """Write CoStar intake diagnostics as current and dated report files."""
    fieldnames = [
        "generated_at",
        "file_name",
        "file_type",
        "file_status",
        "rows_loaded",
        "rows_accepted",
        "rows_skipped",
        "missing_required_fields",
        "notes",
    ]
    rows = COSTAR_INTAKE_DIAGNOSTIC_ROWS or [{
        "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "file_name": "",
        "file_type": "",
        "file_status": "not run",
        "rows_loaded": 0,
        "rows_accepted": 0,
        "rows_skipped": 0,
        "missing_required_fields": "",
        "notes": "CoStar intake was not executed in this run.",
    }]
    write_csv_outputs(
        COSTAR_INTAKE_REPORT_OUTPUT_FILE,
        fieldnames,
        rows,
        dated_output_dir,
    )

    generated_at = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    files_loaded = COSTAR_INTAKE_SUMMARY.get("files_loaded", 0)
    rows_loaded = COSTAR_INTAKE_SUMMARY.get("rows_loaded", 0)
    rows_accepted = COSTAR_INTAKE_SUMMARY.get("rows_accepted", 0)
    rows_skipped = COSTAR_INTAKE_SUMMARY.get("rows_skipped", 0)
    missing_fields = COSTAR_INTAKE_SUMMARY.get("missing_required_fields", "")
    lines = [
        "# CoStar Manual Intake Report",
        "",
        f"Generated: {generated_at}",
        "",
        "This report covers manually exported CoStar files placed in `input/costar/`.",
        "The collector does not scrape CoStar, automate login, or bypass paywalls.",
        "",
        "## Summary",
        "",
        f"- Files loaded: {files_loaded}",
        f"- Rows loaded: {rows_loaded}",
        f"- Rows accepted: {rows_accepted}",
        f"- Rows skipped: {rows_skipped}",
        f"- Missing required fields: {missing_fields or 'None'}",
        "",
        "## File Detail",
        "",
    ]

    for row in rows:
        lines.append(
            f"- {row['file_name'] or 'No file'}: {row['file_status']} | "
            f"loaded {row['rows_loaded']} | accepted {row['rows_accepted']} | "
            f"skipped {row['rows_skipped']} | "
            f"{row['notes'] or 'No notes'}"
        )

    lines.extend([
        "",
        "## Safe Intake Notes",
        "",
        "- Place only files your company is allowed to export or save under its CoStar subscription rights.",
        "- Supported file types: CSV, XLSX, XLS when local Python packages can read them.",
        "- PDF intake is intentionally left for a later version.",
        "",
    ])

    write_markdown_outputs(
        COSTAR_INTAKE_REPORT_MD_OUTPUT_FILE,
        lines,
        dated_output_dir,
    )

    return {
        "files_loaded": files_loaded,
        "rows_loaded": rows_loaded,
        "rows_accepted": rows_accepted,
        "rows_skipped": rows_skipped,
    }


def count_markdown_sections(path):
    """Count Markdown headings as a simple section count."""
    if not os.path.exists(path):
        return 0

    with open(path, mode="r", encoding="utf-8") as file:
        return sum(1 for line in file if line.lstrip().startswith("#"))


def get_file_type(path):
    """Return a beginner-friendly file type label."""
    if path.endswith(".csv"):
        return "CSV"
    if path.endswith(".md"):
        return "Markdown"
    return "Other"


def get_previous_archived_run_data(dated_output_dir):
    """
    Find strategy and market-signal CSVs from the previous archived run.

    If today's dated archive already exists before this run overwrites it, we
    use that as the previous run. Otherwise, we look for the most recent older
    folder under output/runs/.
    """
    current_strategy_path = get_archive_path(
        STRATEGY_BRIEFING_OUTPUT_FILE,
        dated_output_dir,
    )
    current_market_path = get_archive_path(
        MARKET_SIGNALS_OUTPUT_FILE,
        dated_output_dir,
    )

    if os.path.exists(current_strategy_path) and os.path.exists(current_market_path):
        return (
            read_csv_file(current_strategy_path),
            read_csv_file(current_market_path),
            dated_output_dir,
        )

    if not os.path.exists(RUNS_DIR):
        return [], [], ""

    current_folder_name = os.path.basename(dated_output_dir)
    folder_names = sorted(
        [
            folder_name
            for folder_name in os.listdir(RUNS_DIR)
            if os.path.isdir(os.path.join(RUNS_DIR, folder_name))
            and folder_name != current_folder_name
        ],
        reverse=True,
    )

    for folder_name in folder_names:
        folder_path = os.path.join(RUNS_DIR, folder_name)
        strategy_path = get_archive_path(STRATEGY_BRIEFING_OUTPUT_FILE, folder_path)
        market_path = get_archive_path(MARKET_SIGNALS_OUTPUT_FILE, folder_path)

        if os.path.exists(strategy_path) and os.path.exists(market_path):
            return read_csv_file(strategy_path), read_csv_file(market_path), folder_path

    return [], [], ""


def get_previous_archived_file_rows(latest_path, dated_output_dir):
    """
    Read the previous archived copy of a CSV before this run overwrites it.

    This is used for momentum checks such as regime_heatmap.csv comparisons.
    """
    current_archive_path = get_archive_path(latest_path, dated_output_dir)

    if os.path.exists(current_archive_path):
        return read_csv_file(current_archive_path)

    if not os.path.exists(RUNS_DIR):
        return []

    current_folder_name = os.path.basename(dated_output_dir)
    folder_names = sorted(
        [
            folder_name
            for folder_name in os.listdir(RUNS_DIR)
            if os.path.isdir(os.path.join(RUNS_DIR, folder_name))
            and folder_name != current_folder_name
        ],
        reverse=True,
    )

    for folder_name in folder_names:
        archived_path = get_archive_path(
            latest_path,
            os.path.join(RUNS_DIR, folder_name),
        )

        if os.path.exists(archived_path):
            return read_csv_file(archived_path)

    return []


def write_markdown_outputs(path, lines, dated_output_dir):
    """Write a latest Markdown file and optional dated archive copy."""
    write_text_file(path, lines)

    if SAVE_DATED_OUTPUT:
        write_text_file(get_archive_path(path, dated_output_dir), lines)


def append_run_log(
    run_timestamp,
    total_articles,
    high_priority_count,
    market_signal_count,
    strategy_briefing_count,
    llm_prompt_count,
    gpt_analyzed_count,
    output_folder,
):
    """
    Append one run summary row to output/run_log.csv.

    This gives a simple history of each run without opening every dated folder.
    """
    os.makedirs(OUTPUT_DIR, exist_ok=True)
    file_exists = os.path.exists(RUN_LOG_FILE)
    fieldnames = [
        "run_timestamp",
        "total_articles",
        "high_priority_articles",
        "market_signal_articles",
        "strategy_briefing_articles",
        "llm_prompts_generated",
        "gpt_analyzed_articles",
        "gpt_enabled",
        "output_folder",
    ]
    row = {
        "run_timestamp": run_timestamp.strftime("%Y-%m-%d %H:%M:%S"),
        "total_articles": total_articles,
        "high_priority_articles": high_priority_count,
        "market_signal_articles": market_signal_count,
        "strategy_briefing_articles": strategy_briefing_count,
        "llm_prompts_generated": llm_prompt_count,
        "gpt_analyzed_articles": gpt_analyzed_count,
        "gpt_enabled": USE_OPENAI_ANALYSIS,
        "output_folder": output_folder,
    }

    with open(RUN_LOG_FILE, mode="a", newline="", encoding="utf-8-sig") as file:
        writer = csv.DictWriter(file, fieldnames=fieldnames)

        if not file_exists:
            writer.writeheader()

        writer.writerow(row)


def read_run_log_rows():
    """Read output/run_log.csv so trend alerts can compare recent runs."""
    if not os.path.exists(RUN_LOG_FILE):
        return []

    with open(RUN_LOG_FILE, mode="r", newline="", encoding="utf-8-sig") as file:
        return list(csv.DictReader(file))


